C7.current_terraform:
resource "aws_eip" "nat_gw_staging_eip" {
  domain = "vpc"

  tags = {
    Name        = "nat-gw-staging-eip"
    Environment = "staging"
  }
}

resource "aws_nat_gateway" "nat_gw_staging_app" {
  allocation_id = aws_eip.nat_gw_staging_eip.id
  subnet_id     = "subnet-0a1b2c3d"

  tags = {
    Name        = "nat-gw-staging-app"
    Environment = "staging"
  }
}

C8.current_terraform:
resource "aws_lb" "api_staging_alb" {
  name               = "api-staging-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = ["sg-0a1b2c3d"]
  subnets            = ["subnet-0a1b2c3d", "subnet-0b2c3d4e"]

  tags = {
    Name        = "api-staging-alb"
    Environment = "staging"
  }
}

resource "aws_lb_target_group" "api_staging_tg" {
  name     = "api-staging-tg"
  port     = 8080
  protocol = "HTTP"
  vpc_id   = "vpc-0a1b2c3d"

  tags = {
    Name        = "api-staging-tg"
    Environment = "staging"
  }
}

resource "aws_lb_listener" "api_staging_listener" {
  load_balancer_arn = aws_lb.api_staging_alb.arn
  port              = 443
  protocol          = "HTTPS"
  ssl_policy        = "ELBSecurityPolicy-2016-08"
  certificate_arn   = "arn:aws:acm:us-east-1:123456789012:certificate/abc123"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.api_staging_tg.arn
  }
}

C9.current_terraform:
resource "aws_ecr_repository" "api_service" {
  name                 = "api-service"
  image_tag_mutability = "MUTABLE"

  image_scanning_configuration {
    scan_on_push = true
  }

  tags = {
    Name        = "api-service"
    Environment = "production"
  }
}
# No aws_ecr_lifecycle_policy configured

C10.current_terraform:
resource "aws_lambda_function" "order_processor_prod" {
  filename      = "order_processor.zip"
  function_name = "order-processor-prod"
  role          = aws_iam_role.lambda_exec.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"
  memory_size   = 512
  timeout       = 30

  tags = {
    Name        = "order-processor-prod"
    Environment = "production"
  }
}

resource "aws_lambda_provisioned_concurrency_config" "order_processor_prod_pc" {
  function_name              = aws_lambda_function.order_processor_prod.function_name
  qualifier                  = "PROVISIONED"
  provisioned_concurrent_executions = 5
}

